            grep -H . /sys/class/infiniband/*/ports/*/gid_attrs/types/* 2>/dev/null

            KSERVE_INFER_IB_GID_INDEX_GREP=${KSERVE_INFER_IB_GID_INDEX_GREP:-"RoCE v2"}

            echo "[Infer RoCE] Discovering active HCAs ..."
            active_hcas=()
